class Solution:
    def validSequence(self, word1: str, word2: str) -> List[int]:
        seq = []
        diff_count = 0
        for i in range(len(word2)):
            if word1[i] != word2[i]:
                diff_count += 1
                seq.append(i)
            if diff_count > 1:
                return []
        return seq
